var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양의 보고는 이상입니다.","JPN":"シズカさんの報告は以上です。","ENG":"That concludes Seo Yoon's report.","TWN":"以上就是徐芸的報告。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결국 소원구슬은 회수하지 못했군요.","JPN":"結局願い玉は回収できなかったようですね。","ENG":"In a nutshell, we failed to collect the Wishing Ball.","TWN":"結果還是沒能收回許願珠啊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다른 사람 손에 들어가는 것은 막았으니, 일단은 절반의 성공이라고 봐야겠죠.","JPN":"他の人の手に渡ることは防いだので、一旦は半分成功ということで。","ENG":"But we could call it a half success, since we did prevent it from falling into someone else's hands.","TWN":"成功地阻止了許願珠落入他人之手，也可以說是成功了一半。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그거 다행이군.","JPN":"それは良かった。","ENG":"I'm glad to hear that.","TWN":"那就好。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소원구슬은 힘이 유출되지 않게 전용 케이스에 보관됐을 텐데......","JPN":"しかし、願い玉は力が流出しないよう専用ケースに保管していたはずなのに……","ENG":"I assume the Wishing Ball was stored in a special case to prevent power leakage.","TWN":"不過為了防止力量外泄，許願珠應該保管在專用盒子裡吧……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 침식체들이 나타난 거지?","JPN":"どうして侵食体が現れたのだろう？","ENG":"How did it manage to attract the C.O.s?","TWN":"怎麼會出現侵蝕體呢？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확인해 보니 홍보 담당자가 운동회 중간에 케이스를 빼서 버렸다더군요.","JPN":"確認したところ、広報担当者が運動会の途中でケースを外して捨てたそうです。","ENG":"It turned out the PR manager removed and discarded the case halfway through the Field Day.","TWN":"徐芸調查以後發現，宣傳負責人在運動會期間換掉了盒子。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구슬의 반짝이는 모습을 보여주는 게 홍보에 더 도움이 된다면서 말이죠.","JPN":"玉の輝きを見せたほうが宣伝に役に立つと。","ENG":"He thought showing its glowing radiance would help advertise the occasion more effectively.","TWN":"他說露出珠子發光的樣子會對宣傳有幫助。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......누군지 몰라도 안전 불감증이라는 건 확실한 것 같군.","JPN":"……誰なのかは知らないが、危機管理能力が足りないな。","ENG":"Whoever he is, he needs to learn about safety.","TWN":"……雖然不知道是誰，真是缺乏安全意識啊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 그 뒤는 어떻게 됐지?","JPN":"それで、その後はどうなったんだ？","ENG":"What happened afterward?","TWN":"那後來怎麼樣了？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"소원구슬이 가짜라는 소문이 나서 학생들......","JPN":"願い玉が偽物だという噂が流れて、生徒たちが……","ENG":"A rumor spread that the Wishing Ball was a fake, and the students complained about it.","TWN":"都在傳許願珠是假的，學生們……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"특히 나이엘이라는 친구가 크게 항의를 했다고 합니다.","JPN":"特にナイエルという子が激しく抗議したそうです。","ENG":"Especially the one named Naielle.","TWN":"特別是那個叫奈爾的學生，提出了嚴重的抗議。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 아티팩트를 제공한 브라우니라는 선생은 이미 사라져 버렸다더군요.","JPN":"しかし、アーティファクトを提供したブラウニー先生という方はすでに消えてしまったそうです。","ENG":"But the teacher, Brownie, who provided the Artifact had already disappeared.","TWN":"不過聽說提供人造神器的布朗尼老師已經消失了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 쪽지를 남겨 두고 말이죠.","JPN":"こんなメモを残して、です。","ENG":"She left this note.","TWN":"她留下了這樣的紙條。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"안녕! 학생 여러분!","JPN":"こんにちは、生徒のみなさん！","ENG":"Hello, students!","TWN":"大家好！各位同學！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님은 여러분을 너~무 좋아하지만, 아쉽게도 한동안 못 보게 될 것 같아.","JPN":"先生はみんなのことが大好きだけど、残念ながらしばらく会えなくなりそうです。","ENG":"I love you guys very much, but I'll have to leave you for a while.","TWN":"老師很~喜歡你們，不過很可惜，老師有一段時間都不能跟你們見面了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"왜냐하면 이면세계에 굉장한 유적이 발견되었다고 하거든!","JPN":"なぜなら、裏世界でとんでもない遺跡が発見されたらしいの！","ENG":"An incredible site has been discovered on the Counterside!","TWN":"因為我聽說異界發現了偉大的遺跡！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 다른 얼치기들이 선수를 치기 전에......","JPN":"それで他の人に先手を打たれる前に……","ENG":"I'd better go before some idiots beat me to it—","TWN":"所以，在其他半吊子先下手之前……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};